    }
    fn set_lazy_flag(&mut self) {
        self.lazy_flag = true;
    }
}

impl Drop for UserMapArea {
    fn drop(&mut self) {
        if !self.data_frames.is_empty() {
            warn!(
                "[MEMDEBUG] UserMapArea dropped with {} remaining frames, type={:?}, range={:#x}..{:#x}",
                self.data_frames.len(),
                self.area_type,
                self.start_va().0,
                self.end_va().0
            );
        }
    }
}

