impl OpenFlags {
    pub fn writable(&self) -> bool {
        self.bits() & 0o3 != 0
    }

    pub fn read_write(&self) -> (bool, bool) {
        match self.bits() & 0o3 {
            0o1 => (false, true),
            0o2 => (true, true),
            _ => (true, false),
        }
    }
}

